using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT"); // optional, for Azure or compatible APIs

// --- Build the chat client with tools ---
var notes = new NoteStore();

OpenAIClientOptions? options = null;
if (endpoint is not null)
{
    options = new OpenAIClientOptions { Endpoint = new Uri(endpoint) };
}

IChatClient innerClient = new OpenAIClient(apiKey, options)
    .GetChatClient(modelName)
    .AsIChatClient();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearch),
        AIFunctionFactory.Create(notes.SaveNote),
        AIFunctionFactory.Create(notes.GetNotes),
    ]
};

// --- Agent loop ---
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");

while (true)
{
    Console.Write("\n> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a research agent. When given a topic, you:
            1. Search the web multiple times to gather information from different angles.
            2. Save important findings as notes using the save_note tool.
            3. After gathering enough information, retrieve your notes and produce a
               well-structured summary with key points and sources.
            Always search at least 2-3 times with different queries before summarizing.
            """),
        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}")
    };

    Console.WriteLine($"\nResearching \"{topic}\"...\n");

    var response = await agent.GetResponseAsync(messages, chatOptions);

    Console.WriteLine("--- Summary ---");
    Console.WriteLine(response.Text);
    Console.WriteLine("---------------");
}

// --- Tool definitions ---

[Description("Searches the web for the given query and returns a list of result snippets.")]
static string WebSearch([Description("The search query")] string query)
{
    Console.WriteLine($"  [Tool] Web search: \"{query}\"");

    // Simulated search results for demonstration purposes.
    // Replace this with a real search API (e.g., Bing Search API) for production use.
    return $"""
        Search results for "{query}":
        1. Wikipedia overview: "{query}" is a widely discussed topic with multiple facets 
           covering history, current developments, and future outlook.
           Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}
        2. Recent news: Latest developments in "{query}" show significant progress 
           in 2026 with new breakthroughs announced by leading research institutions.
           Source: https://news.example.com/{Uri.EscapeDataString(query)}
        3. Academic paper: A comprehensive review of "{query}" published in Nature 
           highlights key challenges and opportunities ahead.
           Source: https://nature.example.com/articles/{Uri.EscapeDataString(query)}
        """;
}

// --- Note store ---

public class NoteStore
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note for later reference when compiling the summary.")]
    public string SaveNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  [Tool] Retrieving {_notes.Count} note(s)");
        return string.Join("\n---\n", _notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }

    public void Clear() => _notes.Clear();
}

